import { useState } from "react";
const USERS = [
  { email: "jordanmcadoo@nulabs.com", password: "Password01!" },
  { email: "ragenmcadoo@nulabs.com",  password: "Password01!" },
  { email: "rmcadoo@gmail.com",       password: "Password01!" },
  { email: "ccebello@nulabs.com",     password: "Password01!" },
  { email: "ldanieli@nulabs.com",     password: "Password01!" },
];
// Note: variable name kept as "vibratoLogo" for minimal diff; now holds the NUForce logo.
const vibratoLogo = "data:image/png;base64,";
const nuLogo = "data:image/png;base64,";

export default function Login({ onLogin }) {
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [error, setError] = useState("");
  const [showPw, setShowPw] = useState(false);
  const [forgotMode, setForgotMode] = useState(false);
  const [forgotEmail, setForgotEmail] = useState("");
  const [forgotMsg, setForgotMsg] = useState("");

  const handleSubmit = (e) => {
    e.preventDefault();
    const match = USERS.find(u => u.email.toLowerCase() === email.trim().toLowerCase() && u.password === password);
    if (match) { onLogin(match.email); } else { setError("Invalid email or password."); }
  };

  const handleForgot = (e) => {
    e.preventDefault();
    const known = USERS.find(u => u.email.toLowerCase() === forgotEmail.trim().toLowerCase());
    if (known) {
      setForgotMsg("Password reset requests must be handled by your system administrator. Please contact Jordan McAdoo at jordanmcadoo@nulabs.com.");
    } else {
      setForgotMsg("No account found for that email address.");
    }
  };

  const inpStyle = {
    width:"100%", padding:"12px 14px", border:"1px solid #e0e0e0",
    borderRadius:8, fontSize:14, outline:"none", boxSizing:"border-box",
    background:"#f7f7f7", color:"#333"
  };
  const labelStyle = {
    display:"block", fontSize:11, fontWeight:700, color:"#888",
    marginBottom:6, letterSpacing:.8
  };

  if (forgotMode) {
    return (
      <div style={{minHeight:"100vh",display:"flex",alignItems:"center",justifyContent:"center",
        background:"#1a2332",fontFamily:"Segoe UI, system-ui, sans-serif"}}>
        <div style={{background:"#fff",borderRadius:20,padding:"44px 40px",width:400,
          boxShadow:"0 8px 40px rgba(0,0,0,0.35)"}}>
          <div style={{display:"flex",flexDirection:"column",alignItems:"center",marginBottom:28}}>
            <img src={vibratoLogo} alt="NUForce" style={{height:80,width:"auto",objectFit:"contain",marginBottom:10}}/>
            <img src={nuLogo} alt="NU Laboratories" style={{height:30,width:"auto",objectFit:"contain"}}/>
          </div>
          <div style={{textAlign:"center",marginBottom:24}}>
            <div style={{fontWeight:700,fontSize:20,color:"#1a2332"}}>Reset Password</div>
            <div style={{fontSize:13,color:"#888",marginTop:4}}>Sales Portal</div>
          </div>
          {!forgotMsg ? (
            <form onSubmit={handleForgot}>
              <div style={{marginBottom:20}}>
                <label style={labelStyle}>EMAIL</label>
                <input type="email" value={forgotEmail} onChange={e=>setForgotEmail(e.target.value)}
                  placeholder="you@nulabs.com" required autoFocus style={inpStyle}/>
              </div>
              <button type="submit" style={{width:"100%",padding:"14px 0",background:"#c0392b",
                color:"#fff",border:"none",borderRadius:8,fontWeight:700,fontSize:15,cursor:"pointer",
                letterSpacing:.3}}>
                Send Reset Instructions
              </button>
            </form>
          ) : (
            <div style={{background:"#f0fdf4",border:"1px solid #86efac",borderRadius:8,padding:"12px 14px",
              fontSize:13,color:"#15803d",lineHeight:1.6,marginBottom:16}}>
              {forgotMsg}
            </div>
          )}
          <button onClick={()=>{setForgotMode(false);setForgotMsg("");setForgotEmail("");}}
            style={{width:"100%",marginTop:12,padding:"11px 0",background:"none",
              border:"1px solid #e0e0e0",borderRadius:8,fontSize:13,color:"#888",cursor:"pointer"}}>
            ← Back to Sign In
          </button>
        </div>
      </div>
    );
  }

  return (
    <div style={{minHeight:"100vh",display:"flex",alignItems:"center",justifyContent:"center",
      background:"#1a2332",fontFamily:"Segoe UI, system-ui, sans-serif"}}>
      <div style={{background:"#fff",borderRadius:20,padding:"44px 40px",width:400,
        boxShadow:"0 8px 40px rgba(0,0,0,0.35)"}}>

        {/* Logos */}
        <div style={{display:"flex",flexDirection:"column",alignItems:"center",marginBottom:20}}>
          <img src={vibratoLogo} alt="NUForce" style={{height:80,width:"auto",objectFit:"contain",marginBottom:10}}/>
          <img src={nuLogo} alt="NU Laboratories" style={{height:30,width:"auto",objectFit:"contain"}}/>
        </div>

        {/* Sign in heading */}
        <div style={{textAlign:"center",marginBottom:28}}>
          <div style={{fontWeight:700,fontSize:20,color:"#1a2332"}}>Sign in</div>
          <div style={{fontSize:13,color:"#888",marginTop:4}}>Sales Portal</div>
        </div>

        <form onSubmit={handleSubmit}>
          <div style={{marginBottom:16}}>
            <label style={labelStyle}>EMAIL</label>
            <input type="email" value={email} onChange={e=>setEmail(e.target.value)}
              placeholder="you@nulabs.com" required autoFocus style={inpStyle}/>
          </div>
          <div style={{marginBottom:20}}>
            <label style={labelStyle}>PASSWORD</label>
            <div style={{position:"relative"}}>
              <input type={showPw?"text":"password"} value={password} onChange={e=>setPassword(e.target.value)}
                placeholder="••••••••••" required
                style={{...inpStyle,paddingRight:60}}/>
              <button type="button" onClick={()=>setShowPw(p=>!p)}
                style={{position:"absolute",right:12,top:"50%",transform:"translateY(-50%)",
                  background:"none",border:"none",cursor:"pointer",color:"#888",fontSize:13,fontWeight:600}}>
                {showPw?"Hide":"Show"}
              </button>
            </div>
          </div>
          {error&&<div style={{background:"#fdf3f2",border:"1px solid #e74c3c44",borderRadius:6,
            padding:"8px 12px",fontSize:12,color:"#c0392b",marginBottom:16}}>{error}</div>}
          <button type="submit" style={{width:"100%",padding:"14px 0",background:"#c0392b",
            color:"#fff",border:"none",borderRadius:8,fontWeight:700,fontSize:15,cursor:"pointer",
            letterSpacing:.3}}>
            Sign In
          </button>
        </form>

        <div style={{marginTop:16,textAlign:"center"}}>
          <button onClick={()=>{setForgotMode(true);setError("");}}
            style={{background:"none",border:"none",color:"#c0392b",fontSize:12,cursor:"pointer",
              textDecoration:"none",padding:0,fontWeight:500}}>
            Forgot password?
          </button>
        </div>

        <div style={{marginTop:20,fontSize:11,color:"#bbb",textAlign:"center"}}>
          NU Laboratories · Internal Use Only
        </div>
      </div>
    </div>
  );
}
